%%%%%%%%%% Function fTrexGnrInfV01.m %%%%%%%%%%% Function Figure General Information, ver.1% Kei Nakamura% Created on Saturday, June 9th 2007.% Modified on %% function inf = fTrexGnrInfV01(sig);% returns a information string for figure%function inf = fTrexGnrInfV01(dat);  %function headerinf{1} = strcat('shot number:',num2str(floor(dat(1))));inf{2} = strcat('total charge [pC]:',num2str(0.1*floor(10*dat(2))));inf{3} = strcat('total energy [mJ]:',num2str(0.1*floor(10*dat(3))));inf{4} = strcat('roi charge [pC]:',num2str(0.1*floor(10*dat(4))));inf{5} = strcat('roi energy [mJ]:',num2str(0.1*floor(10*dat(5))));
